import React, { useEffect, useState, useRef } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useSelector, useDispatch } from 'react-redux';
import { updateUser } from '../store/authSlice';
import { jobsAPI, userAPI } from '../services/api';

function StatCard({ icon, value, label, color = 'purple' }) {
  const colors = {
    purple: 'from-purple-600/20 to-purple-500/5 border-purple-500/20',
    green: 'from-green-600/20 to-green-500/5 border-green-500/20',
    blue: 'from-blue-600/20 to-blue-500/5 border-blue-500/20',
    yellow: 'from-yellow-600/20 to-yellow-500/5 border-yellow-500/20',
  };
  return (
    <div className={`rounded-2xl border bg-gradient-to-br p-5 ${colors[color]}`}>
      <div className="text-2xl mb-2">{icon}</div>
      <div className="text-2xl font-bold text-white">{value}</div>
      <div className="text-gray-400 text-xs mt-0.5">{label}</div>
    </div>
  );
}

export default function Dashboard() {
  const { user } = useSelector((state) => state.auth);
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const [stats, setStats] = useState({ applied: 0, saved: 0, jobs: 0 });
  const [csvFile, setCsvFile] = useState(null);
  const [csvLoading, setCsvLoading] = useState(false);
  const [csvMsg, setCsvMsg] = useState('');
  const [resumeFile, setResumeFile] = useState(null);
  const [resumeLoading, setResumeLoading] = useState(false);
  const [resumeMsg, setResumeMsg] = useState('');
  const fileRef = useRef(null);
  const resumeRef = useRef(null);

  useEffect(() => {
    async function loadStats() {
      try {
        const [appliedRes, savedRes, jobsRes] = await Promise.allSettled([
          import('../services/api').then(m => m.applicationsAPI.getApplications({ action: 'applied' })),
          import('../services/api').then(m => m.applicationsAPI.getApplications({ action: 'saved' })),
          import('../services/api').then(m => m.jobsAPI.getJobs({ limit: 1 })),
        ]);
        setStats({
          applied: appliedRes.status === 'fulfilled' ? appliedRes.value.data.applications.length : 0,
          saved: savedRes.status === 'fulfilled' ? savedRes.value.data.applications.length : 0,
          jobs: jobsRes.status === 'fulfilled' ? jobsRes.value.data.total : 0,
        });
      } catch (_) {}
    }
    loadStats();
  }, []);

  const handleCsvUpload = async () => {
    if (!csvFile) return;
    setCsvLoading(true);
    setCsvMsg('');
    try {
      const fd = new FormData();
      fd.append('csv', csvFile);
      const res = await jobsAPI.uploadCSV(fd);
      setCsvMsg(`✅ ${res.data.message}`);
      setCsvFile(null);
    } catch (err) {
      setCsvMsg(`❌ ${err.response?.data?.message || 'Upload failed'}`);
    } finally {
      setCsvLoading(false);
    }
  };

  const handleResumeUpload = async () => {
    if (!resumeFile) return;
    setResumeLoading(true);
    setResumeMsg('');
    try {
      const fd = new FormData();
      fd.append('resume', resumeFile);
      const res = await userAPI.uploadResume(fd);
      dispatch(updateUser(res.data.user));
      setResumeMsg(`✅ Found ${res.data.extractedSkills.length} skills: ${res.data.extractedSkills.slice(0, 5).join(', ')}${res.data.extractedSkills.length > 5 ? '...' : ''}`);
      setResumeFile(null);
    } catch (err) {
      setResumeMsg(`❌ ${err.response?.data?.message || 'Upload failed'}`);
    } finally {
      setResumeLoading(false);
    }
  };

  const greeting = () => {
    const h = new Date().getHours();
    if (h < 12) return '🌅 Good morning';
    if (h < 17) return '☀️ Good afternoon';
    return '🌙 Good evening';
  };

  return (
    <div className="page-bg pt-20 pb-10 px-4 min-h-screen">
      <div className="max-w-5xl mx-auto animate-fade-in">
        {/* Welcome header */}
        <div className="mb-8">
          <p className="text-gray-400 text-sm">{greeting()},</p>
          <h1 className="text-3xl font-bold text-white mt-1">
            {user?.name?.split(' ')[0] || 'There'} 👋
          </h1>
          {user?.college && (
            <p className="text-gray-500 text-sm mt-1">📚 {user.college} {user.degree && `· ${user.degree}`}</p>
          )}
        </div>

        {/* Stats */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
          <StatCard icon="💼" value={stats.jobs.toLocaleString()} label="Live Opportunities" color="purple" />
          <StatCard icon="✅" value={stats.applied} label="Jobs Applied" color="green" />
          <StatCard icon="⭐" value={stats.saved} label="Jobs Saved" color="yellow" />
          <StatCard icon="🧠" value={user?.skills?.length || 0} label="Skills Detected" color="blue" />
        </div>

        <div className="grid md:grid-cols-2 gap-6">
          {/* Skills card */}
          <div className="glass-card p-6">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-white font-semibold">🧠 Your Skills</h2>
              <button onClick={() => resumeRef.current?.click()}
                className="text-xs text-purple-400 hover:text-purple-300">
                Update Resume →
              </button>
            </div>
            {user?.skills?.length > 0 ? (
              <div className="flex flex-wrap gap-1.5">
                {user.skills.map((skill, i) => (
                  <span key={i} className="px-3 py-1 rounded-lg text-xs bg-purple-500/15 text-purple-300 border border-purple-500/20">
                    {skill}
                  </span>
                ))}
              </div>
            ) : (
              <div className="text-center py-6">
                <div className="text-3xl mb-2">📄</div>
                <p className="text-gray-400 text-sm">Upload your resume to auto-detect skills</p>
                <button
                  onClick={() => resumeRef.current?.click()}
                  className="btn-primary mt-3 text-sm py-2 px-4"
                >
                  Upload Resume
                </button>
              </div>
            )}

            {/* Hidden resume input */}
            <input ref={resumeRef} type="file" accept=".pdf,.docx,.doc" className="hidden"
              onChange={(e) => setResumeFile(e.target.files[0])} />
            {resumeFile && (
              <div className="mt-3 p-3 rounded-xl bg-purple-500/10 border border-purple-500/20">
                <p className="text-purple-300 text-xs mb-2">📄 {resumeFile.name}</p>
                <button onClick={handleResumeUpload} disabled={resumeLoading}
                  className="btn-primary text-xs py-1.5 px-4 w-full disabled:opacity-50">
                  {resumeLoading ? 'Parsing...' : 'Parse & Update Skills'}
                </button>
              </div>
            )}
            {resumeMsg && <p className="text-xs mt-2 text-gray-300">{resumeMsg}</p>}
          </div>

          {/* Quick actions */}
          <div className="space-y-4">
            <div className="glass-card p-6">
              <h2 className="text-white font-semibold mb-4">🚀 Quick Actions</h2>
              <div className="space-y-2">
                <Link to="/jobs" className="flex items-center justify-between p-3.5 rounded-xl bg-purple-500/10 hover:bg-purple-500/20 transition-colors group">
                  <span className="text-gray-300 text-sm group-hover:text-white">Browse Live Jobs →</span>
                  <span className="text-purple-400">💼</span>
                </Link>
                <Link to="/jobs?type=internship" className="flex items-center justify-between p-3.5 rounded-xl bg-orange-500/10 hover:bg-orange-500/20 transition-colors group">
                  <span className="text-gray-300 text-sm group-hover:text-white">Find Internships →</span>
                  <span>🎓</span>
                </Link>
                <Link to="/jobs?type=scholarship" className="flex items-center justify-between p-3.5 rounded-xl bg-yellow-500/10 hover:bg-yellow-500/20 transition-colors group">
                  <span className="text-gray-300 text-sm group-hover:text-white">Explore Scholarships →</span>
                  <span>🏅</span>
                </Link>
                <Link to="/applications" className="flex items-center justify-between p-3.5 rounded-xl bg-green-500/10 hover:bg-green-500/20 transition-colors group">
                  <span className="text-gray-300 text-sm group-hover:text-white">My Applications →</span>
                  <span>📋</span>
                </Link>
              </div>
            </div>

            {/* CSV Upload */}
            <div className="glass-card p-6">
              <h2 className="text-white font-semibold mb-1">📄 Upload Job CSV</h2>
              <p className="text-gray-500 text-xs mb-3">Add your own job listings. Columns: title, company, apply_url, type, location, salary, description, tags, is_remote</p>
              <div
                className="drop-zone p-4 text-center cursor-pointer"
                onClick={() => fileRef.current?.click()}
              >
                {csvFile ? (
                  <p className="text-purple-300 text-sm">📄 {csvFile.name}</p>
                ) : (
                  <p className="text-gray-500 text-xs">Click to select CSV file</p>
                )}
              </div>
              <input ref={fileRef} type="file" accept=".csv" className="hidden"
                onChange={(e) => { setCsvFile(e.target.files[0]); setCsvMsg(''); }} />
              {csvFile && (
                <button onClick={handleCsvUpload} disabled={csvLoading}
                  className="btn-primary w-full mt-3 text-sm py-2 disabled:opacity-50">
                  {csvLoading ? 'Importing...' : '⬆️ Import CSV'}
                </button>
              )}
              {csvMsg && <p className="text-xs mt-2 text-gray-300">{csvMsg}</p>}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
